  ('social-worker-moex-08180', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '看到有些抽了一輩子菸的長壽健康老人，因而否定抽菸會增加肺癌風險機率的醫學研究結論，這種推論：', '["是一種化約論", "是區位謬誤", "是個體主義的謬誤", "是目的論"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08181', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '進行身心障礙者生活狀況調查時，針對較罕見的身心障礙類別，給予較高的抽選機率，以保證這些類別有 充分的個案被選出，類別之間可以比較，下列敘述何者不正確？', '["因為每個個體被選出的機率其實不等，不是機率樣本", "是一種非等比例分層抽樣", "進行母體參數估計時要注意各類別機率不等的權數調整", "抽樣機率不影響類別之間的比較"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08182', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為了解我國實施國民年金政策是否提升國民對於老年生活的經濟安全感，下列何種研究設計，比較可行且 可得到較有效的結論？', '["隨機選擇部分地區為對照組，暫緩實施數年，以比較和實施地區的差異", "辦理全國性抽樣調查了解國民感受", "簡單時間序列設計，在政策實施前後，多元時間點測量國民態度", "和別的國家比較"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08183', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '調查或訪談中，針對開放式問項訪談中不完整或糢糊的答案，使用刺探問法（probe），下列何者是不正確 的作法？', '["目的在誘發更多的答案和說詞", "問法是中立的", "問法是具有鼓勵性的", "問法是具有指導性的"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08184', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '我國歷年用以訂定家庭低收入標準的家庭收支調查，在研究設計上屬於一種：', '["橫斷面研究（cross-sectional study）", "趨勢性研究（trend study）", "固定名單研究（panel study）", "世代研究（cohort study）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
